const allExamples: TrainingExample[] = [
  ...floridaLaw,
  ...offerNegotiation,
  ...inspection,
  ...mortgageFinancing,
  ...appraisal,
  ...titleClosing,
  ...platformSpecific,
  ...emotionalComplex,
  ...postClosing,
  ...marketAnalysis,
];

/**
 * Generates the JSONL training file and saves it to disk.
 * Returns the file path.
 */
export async function generateTrainingData(): Promise<string> {
  const outputDir = path.join(process.cwd(), "training-data");
  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  const outputPath = path.join(outputDir, "real-estate-knowledge.jsonl");
  const lines = allExamples.map((example) => JSON.stringify(example));
  fs.writeFileSync(outputPath, lines.join("\n"), "utf-8");

  console.log(`[Training Data] Generated ${allExamples.length} training examples → ${outputPath}`);
  return outputPath;
}

/**
 * Returns training examples as an array (for testing/preview).
 */
export function getTrainingExamples(): TrainingExample[] {
  return allExamples;
}

/**
 * Returns the count of training examples.
 */
export function getTrainingDataCount(): number {
  return allExamples.length;
}
